Array.move=function(e,n,t){if(t>=e.length){var r=t-e.length;while(r--+1){e.push(undefined)}}e.splice(t,0,e.splice(n,1)[0]);return e};Array.removeIndexed=function(e,n,t){var r=e.slice((t||n)+1||e.length);e.length=n<0?e.length+n:n;e.push.apply(e,r);return e};Array.remove=function(e,n){let t=e.findIndex(e=>e===n);if(t>=0){Array.removeIndexed(e,t,t)}return e};Array.unique=function(e){return e.filter((e,n,t)=>t.indexOf(e)===n)};Array.clone=Array.from;Number.random=function(e,n){return Math.floor(Math.random()*(n-e+1))+e};Element.byId=function(e){return document.getElementById(e)};Element.byTag=function(e){return document.body.getElementsByTagName(e)};Element.hasClass=function(e,n){n=n.trim();return e.className.split(" ").includes(n)};Element.addClass=function(e,n){if(!Element.hasClass(e,n)){e.className+=" "+n}};Element.removeClass=function(e,n){n=n.trim();e.className=e.className.split(" ").filter(e=>e!=n).join(" ")};Element.toggleClass=function(e,n){n=n.trim();let t=Element;t.hasClass(e,n)?t.removeClass(e,n):t.addClass(e,n)};Object.clone=function(e){if(Array.isArray(e))return Array.clone(e);let n={};Object.entries(e).forEach(([e,t])=>n[e]=t!==null&&typeof t==="object"?Object.clone(t):t);return n};